function [Output1, Output2] = unBuf (Input)
%% ************************************************************************
% Unbuffer function
% Outputs first received serial data from buffer for both signals

% Copyright 2020 The MathWorks, Inc.

selSignal= Input(:, 1);
Output1 = selSignal(1,1);
selSignal = Input(:, 2);
Output2 = selSignal(1,1);
end
